.0.1:8000/media/editor/04630f5f-1354-4c17-b10a-ba543e9bb4a3_image.png", "title": null, "width": null, "height": null}}, {"type": "caption", "content": [{"text": "JUSTTTTTTTTTTTTTTTTTTTTTT", "type": "text"}]}]}, {"type": "equation", "attrs": {"label": "Equation 1", "refId": "eq-1"}, "content": [{"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "E=mc^{2}", "type": "text"}]}, {"type": "caption", "content": [{"text": "Energy-Mass reln", "type": "text"}]}]}, {"type": "paragraph", "attrs": {"textAlign": null}}, {"type": "heading", "attrs": {"level": 1, "textAlign": null}, "content": [{"text": "OBJECTIVE", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "·       Set up Linux environment either directly or using VM.", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": " ", "type": "text"}]}, {"type": "heading", "attrs": {"level": 1, "textAlign": null}, "content": [{"text": "OPERATING SYSTEM REQUIRED", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "·       Linux Ubuntu 22.04", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": " ", "type": "text"}]}, {"type": "heading", "attrs": {"level": 1, "textAlign": null}, "content": [{"text": "THEORY", "type": "text"}]}, {"type": "heading", "attrs": {"level": 2, "textAlign": null}, "content": [{"text": "Linux", "type": "text", "marks": [{"type": "bold"}]}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "A Linux is a versatile open-source, Unix-like operating system kernel that powers various distributions (e.g., Ubuntu, Fedora). It's widely used for servers, desktops, and embedded systems due to its stability, flexibility, and security. It is ideal for development, servers, and Big Data platforms like Hadoop, offering robust performance, flexibility, and compatibility for distributed computing.", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": " ", "type": "text", "marks": [{"type": "bold"}]}]}, {"type": "heading", "attrs": {"level": 2, "textAlign": null}, "content": [{"text": "Ubuntu", "type": "text", "marks": [{"type": "bold"}]}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Ubuntu is a free and open-source operating system based on Linux. It is widely used for personal computers, servers, and cloud computing. It comes with built-in software and tools, supports regular updates, and allows customization to suit different needs.", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}}, {"type": "heading", "attrs": {"level": 2, "textAlign": null}, "content": [{"text": "Virtual Machine (VM)", "type": "text", "marks": [{"type": "bold"}]}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "A virtual machine (VM) is software that allows us to run a separate operating system within our current system, acting like a computer inside the computer. It creates a virtual environment where different operating systems, such as Windows or Linux, can be installed and used without affecting our main system. VMs are often used for testing software, running multiple systems on one device and enhancing security. It uses software instead of hardware to run programs and deploy applications.", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": " ", "type": "text"}]}, {"type": "heading", "attrs": {"level": 1, "textAlign": null}, "content": [{"text": "SYSTEM SPECIFICATION", "type": "text"}]}, {"type": "heading", "attrs": {"level": 2, "textAlign": null}, "content": [{"text": "1.     Basic System Specification", "type": "text", "marks": [{"type": "bold"}]}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "·       Command: whoami", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Purpose: To display the username of the current user", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Output: ayush-bhandari", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "·       Command: hostname", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Purpose: To display the hostname", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Output: ayush-bhandari-VMware-Virtual-Platform", "type": "text"}]}, {"type": "figure", "attrs": {"src": "", "label": "Figure 2", "refId": "fig-2"}, "content": [{"type": "image", "attrs": {"alt": null, "src": "http://127.0.0.1:8000/media/editor/84d93280-f505-40e1-81a1-ff27f94a8801_image.png", "title": null, "width": "80%", "height": null}}, {"type": "caption", "content": [{"text": "Ubuntu VM’s username and host", "type": "text"}]}]}, {"type": "paragraph", "attrs": {"textAlign": null}}, {"type": "heading", "attrs": {"level": 2, "textAlign": null}, "content": [{"text": "2.     Ubuntu Version", "type": "text", "marks": [{"type": "bold"}]}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "·       Command: lsb_release -a", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Purpose: To display the detailed information about the Linux distribution currently running on the system. Specifically, it provides information from the Linux Standard Base (LSB).", "type": "text"}]}, {"type": "heading", "attrs": {"level": 3, "textAlign": null}, "content": [{"text": "Key specifications:", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "-        Distributer ID: Ubuntu", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "-        Release: 24.04", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "-        Codename: Noble", "type": "text"}]}, {"type": "figure", "attrs": {"src": "", "label": "Figure 3", "refId": "fig-3"}, "content": [{"type": "image", "attrs": {"alt": null, "src": "http://127.0.0.1:8000/media/editor/c25e2e92-d5a4-4dad-a7e2-c215eed134d1_image.png", "title": null, "width": "75%", "height": null}}, {"type": "caption", "content": [{"text": "Ubuntu version and its image", "type": "text"}]}]}, {"type": "paragraph", "attrs": {"textAlign": null}}, {"type": "heading", "attrs": {"level": 2, "textAlign": null}, "content": [{"text": "3.     CPU Configuration", "type": "text", "marks": [{"type": "bold"}]}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "·       Command: lscpu", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Purpose: To display detailed information about the CPU architecture of the system.", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Key specifications:", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "-        Architecture: x86_64", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "-        Number of CPU cores: 2 cores", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "-        CPU Model: 11th Gen Intel(R) Core(TM) i5-1135G7 @ 2.40GHz", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "-        Virtualization: VMware", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "-        Thread(s) per core: 1", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "-        Core(s) per socket: 1", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "-        Socket(s): 2", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}}, {"type": "heading", "attrs": {"level": 2, "textAlign": null}, "content": [{"text": "4.     Memory (RAM) Information", "type": "text", "marks": [{"type": "bold"}]}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "·       Command: free -h", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Purpose: To display information about the system's memory usage, including RAM and swap memory.", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Key specifications:", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "-        Total RAM: 3.8 GB", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "-        Available RAM: 2.5 GB", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "-        Used: 1.3 GB", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "-        Buffer/Cache: 2 GB", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "-        Swap Space: 3.8 GB", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}}, {"type": "heading", "attrs": {"level": 2, "textAlign": null}, "content": [{"text": "5.     Storage Information", "type": "text", "marks": [{"type": "bold"}]}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "·       Command: df -h", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Purpose: To display information about the disk space usage on the system.", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Key specifications:", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "-        Total allocated storage: 25 GB (/dev/sda2)", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "-        Used storage: 9.6 GB", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "-        Available storage: 14 GB", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "-        Usage percentage: 42%", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}}, {"type": "heading", "attrs": {"level": 2, "textAlign": null}, "content": [{"text": "6.     Operating System Details", "type": "text", "marks": [{"type": "bold"}]}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "·       Command: lsb_release -d", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Purpose: To display the description of the Linux distribution", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Output:", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "            No LSB modules are available.", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Description:    Ubuntu 24.04.1 LTS", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "·       Command: sudo dmidecode -s system-product-name", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Purpose: To extract hardware details, including the virtualization platform.", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Output: VMware Virtual Platform", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "·       Command: uname -m", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Purpose: To display the system architecture", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Output: x86_64", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}}, {"type": "heading", "attrs": {"level": 2, "textAlign": null}, "content": [{"text": "7.     Summarized System Information", "type": "text", "marks": [{"type": "bold"}]}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "·       Command: notefetch", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "Purpose: To display to the system’s summary in a visually appealing format.", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}}, {"type": "heading", "attrs": {"level": 1, "textAlign": null}, "content": [{"text": "RESULT AND DISCUSSION", "type": "text", "marks": [{"type": "bold"}]}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "In this lab, VMWare was used to create a VM in Windows 11. As a VM allows other operating system to run without affecting the original system, Ubuntu LTS x64 22.04 was installed. The VM was set according to the required specifications. Also, the required specifications were verified using the commands like ", "type": "text"}, {"text": "hostname", "type": "text", "marks": [{"type": "italic"}]}, {"text": ", ", "type": "text"}, {"text": "whoami", "type": "text", "marks": [{"type": "italic"}]}, {"text": ", ", "type": "text"}, {"text": "lscpu", "type": "text", "marks": [{"type": "italic"}]}, {"text": ", ", "type": "text"}, {"text": "free", "type": "text", "marks": [{"type": "italic"}]}, {"text": ", ", "type": "text"}, {"text": "df", "type": "text", "marks": [{"type": "italic"}]}, {"text": ", etc. Using these commands, system details including CPU, memory, and storage to get the detailed system information of the Linux based system. Also, I knew that the Linux system is widely preferred for the big data technologies.", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "As shown in ", "type": "text"}, {"type": "reference", "attrs": {"text": "Figure 1", "target": "fig-1"}}, {"text": ", we can see ...", "type": "text"}]}, {"type": "paragraph", "attrs": {"textAlign": null}}, {"type": "heading", "attrs": {"level": 1, "textAlign": null}, "content": [{"text": "CONCLUSION", "type": "text", "marks": [{"type": "bold"}]}]}, {"type": "paragraph", "attrs": {"textAlign": null}, "content": [{"text": "In this way, Ubuntu system can be installed in VM and various specifications can be verified.", "type": "text"}]}]}	<h1>TOC</h1><div label="Table 1" refid="tbl-1" data-labeled-table="" data-label="Table 1" data-ref-id="tbl-1"><table style="width: 350px;"><colgroup><col style="width: 72px;"><col style="width: 278px;"></colgroup><tbody><tr><td colspan="1" rowspan="1" colwidth="72"><p>S.N,</p></td><td colspan="1" rowspan="1" colwidth="278"><p>Heading2</p></td></tr><tr><td colspan="1" rowspan="1" colwidth="72"><p>1</p></td><td colspan="1" rowspan="1" colwidth="278"><p><strong>OBJECTIVE</strong></p></td></tr><tr><td colspan="1" rowspan="1" colwidth="72"><p>2</p></td><td colspan="1" rowspan="1" colwidth="278"><p><strong>OPERATING SYSTEM REQUIRED</strong></p></td></tr><tr><td colspan="1" rowspan="1" colwidth="72"><p>3</p></td><td colspan="1" rowspan="1" colwidth="278"><p></p></td></tr><tr><td colspan="1" rowspan="1" colwidth="72"><p>4</p></td><td colspan="1" rowspan="1" colwidth="278"><p></p></td></tr><tr><td colspan="1" rowspan="1" colwidth="72"><p>5</p></td><td colspan="1" rowspan="1" colwidth="278"><p></p></td></tr><tr><td colspan="1" rowspan="1" colwidth="72"><p>6</p></td><td colspan="1" rowspan="1" colwidth="278"><p></p></td></tr></tbody></table><figcaption data-caption="">TOC of Report</figcaption></div><figure src="" label="Figure 1" refid="fig-1" data-figure="" data-src="" data-label="Figure 1" data-ref-id="fig-1"><img src=""><figcaption><img src="http://127.0.0.1:8000/media/editor/04630f5f-1354-4c17-b10a-ba543e9bb4a3_image.png"><figcaption data-caption="">JUSTTTTTTTTTTTTTTTTTTTTTT</figcaption></figcaption></figure><div label="Equation 1" refid="eq-1" data-equation="" data-label="Equation 1" data-ref-id="eq-1" class="equation-block"><p>E=mc^{2}</p><figcaption data-caption="">Energy-Mass reln</figcaption></div><p></p><h1>OBJECTIVE</h1><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Set up Linux environment either directly or using VM.</p><p>&nbsp;</p><h1>OPERATING SYSTEM REQUIRED</h1><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Linux Ubuntu 22.04</p><p>&nbsp;</p><h1>THEORY</h1><h2><strong>Linux</strong></h2><p>A Linux is a versatile open-source, Unix-like operating system kernel that powers various distributions (e.g., Ubuntu, Fedora). It's widely used for servers, desktops, and embedded systems due to its stability, flexibility, and security. It is ideal for development, servers, and Big Data platforms like Hadoop, offering robust performance, flexibility, and compatibility for distributed computing.</p><p><strong>&nbsp;</strong></p><h2><strong>Ubuntu</strong></h2><p>Ubuntu is a free and open-source operating system based on Linux. It is widely used for personal computers, servers, and cloud computing. It comes with built-in software and tools, supports regular updates, and allows customization to suit different needs.</p><p></p><h2><strong>Virtual Machine (VM)</strong></h2><p>A virtual machine (VM) is software that allows us to run a separate operating system within our current system, acting like a computer inside the computer. It creates a virtual environment where different operating systems, such as Windows or Linux, can be installed and used without affecting our main system. VMs are often used for testing software, running multiple systems on one device and enhancing security. It&nbsp;uses software instead of hardware to run programs and deploy applications.</p><p>&nbsp;</p><h1>SYSTEM SPECIFICATION</h1><h2><strong>1.&nbsp;&nbsp;&nbsp;&nbsp; Basic System Specification</strong></h2><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Command: whoami</p><p>Purpose: To display the username of the current user</p><p>Output: ayush-bhandari</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Command: hostname</p><p>Purpose: To display the hostname</p><p>Output: ayush-bhandari-VMware-Virtual-Platform</p><figure src="" label="Figure 2" refid="fig-2" data-figure="" data-src="" data-label="Figure 2" data-ref-id="fig-2"><img src=""><figcaption><img src="http://127.0.0.1:8000/media/editor/84d93280-f505-40e1-81a1-ff27f94a8801_image.png" width="80%"><figcaption data-caption="">Ubuntu VM’s username and host</figcaption></figcaption></figure><p></p><h2><strong>2.&nbsp;&nbsp;&nbsp;&nbsp; Ubuntu Version</strong></h2><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Command: lsb_release -a</p><p>Purpose: To display the detailed information about the Linux distribution currently running on the system. Specifically, it provides information from the Linux Standard Base (LSB).</p><h3>Key specifications:</h3><p>-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Distributer ID: Ubuntu</p><p>-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Release: 24.04</p><p>-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Codename: Noble</p><figure src="" label="Figure 3" refid="fig-3" data-figure="" data-src="" data-label="Figure 3" data-ref-id="fig-3"><img src=""><figcaption><img src="http://127.0.0.1:8000/media/editor/c25e2e92-d5a4-4dad-a7e2-c215eed134d1_image.png" width="75%"><figcaption data-caption="">Ubuntu version and its image</figcaption></figcaption></figure><p></p><h2><strong>3.&nbsp;&nbsp;&nbsp;&nbsp; CPU Configuration</strong></h2><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Command: lscpu</p><p>Purpose: To display detailed information about the CPU architecture of the system.</p><p>Key specifications:</p><p>-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Architecture: x86_64</p><p>-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Number of CPU cores: 2 cores</p><p>-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; CPU Model: 11th Gen Intel(R) Core(TM) i5-1135G7 @ 2.40GHz</p><p>-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Virtualization: VMware</p><p>-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Thread(s) per core: 1</p><p>-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Core(s) per socket: 1</p><p>-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Socket(s): 2</p><p></p><h2><strong>4.&nbsp;&nbsp;&nbsp;&nbsp; Memory (RAM) Information</strong></h2><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Command: free -h</p><p>Purpose: To display information about the system's memory usage, including RAM and swap memory.</p><p>Key specifications:</p><p>-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Total RAM: 3.8 GB</p><p>-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Available RAM: 2.5 GB</p><p>-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Used: 1.3 GB</p><p>-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Buffer/Cache: 2 GB</p><p>-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Swap Space: 3.8 GB</p><p></p><h2><strong>5.&nbsp;&nbsp;&nbsp;&nbsp; Storage Information</strong></h2><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Command: df -h</p><p>Purpose: To display information about the disk space usage on the system.</p><p>Key specifications:</p><p>-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Total allocated storage: 25 GB (/dev/sda2)</p><p>-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Used storage: 9.6 GB</p><p>-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Available storage: 14 GB</p><p>-&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Usage percentage: 42%</p><p></p><h2><strong>6.&nbsp;&nbsp;&nbsp;&nbsp; Operating System Details</strong></h2><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Command: lsb_release -d</p><p>Purpose: To display the description of the Linux distribution</p><p>Output:</p><p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; No LSB modules are available.</p><p>Description:&nbsp;&nbsp;&nbsp; Ubuntu 24.04.1 LTS</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Command: sudo dmidecode -s system-product-name</p><p>Purpose: To extract hardware details, including the virtualization platform.</p><p>Output: VMware Virtual Platform</p><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Command: uname -m</p><p>Purpose: To display the system architecture</p><p>Output: x86_64</p><p></p><h2><strong>7.&nbsp;&nbsp;&nbsp;&nbsp; Summarized System Information</strong></h2><p>·&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Command: notefetch</p><p>Purpose: To display to the system’s summary in a visually appealing format.</p><p></p><h1><strong>RESULT AND DISCUSSION</strong></h1><p>In this lab, VMWare was used to create a VM in Windows 11. As a VM allows other operating system to run without affecting the original system, Ubuntu LTS x64 22.04 was installed. The VM was set according to the required specifications. Also, the required specifications were verified using the commands like <em>hostname</em>, <em>whoami</em>, <em>lscpu</em>, <em>free</em>, <em>df</em>, etc. Using these commands, system details including CPU, memory, and storage to get the detailed system information of the Linux based system. Also, I knew that the Linux system is widely preferred for the big data technologies.</p><p>As shown in <span target="fig-1" text="Figure 1" data-ref="fig-1" class="reference-link text-blue-600 underline cursor-pointer">[Figure 1]</span>, we can see ...</p><p></p><h1><strong>CONCLUSION</strong></h1><p>In this way, Ubuntu system can be installed in VM and various specifications can be verified.</p>	1	1		en	d53dbabe-e6f8-46c0-87e7-925ffadf9057
\.


